import React, { useEffect, useRef } from 'react';
import '../Styling/Timeline.css';

const timelineData = [
    {
        year: 'Oct. 1983',
        title: 'Founding of the Journal of Law & Politics',
        description: 'The Journal of Law & Politics is founded under the guidance of Supreme Court Justice Antonin Scalia.',
        category: 'Legacy'
    },
    {
        year: 'Sep. 2024',
        title: 'UJLP Founded',
        description: 'UJLP is founded as the undergraduate affiliate of the Journal of Law & Politics.',
        category: 'Establishment'
    },
    {
        year: 'Oct. 2024',
        title: 'Digital Platform Launch',
        description: 'UJLP launches its digital platform to improve accessibility and work towards its mission of expanding undergraduate legal scholarship.',
        category: 'Innovation'
    },
    {
        year: 'Nov. 2024',
        title: 'Founding Members Selected',
        description: 'UJLP selects its founding members and begins developing the publication infrastructure.',
        category: 'Milestone'
    },
    {
        year: 'Jan. 2025',
        title: 'First Speaker Event',
        description: 'UJLP hosts its first speaker event featuring an S.J.D. candidate from the UVA School of Law.',
        category: 'Events'
    },
    {
        year: 'Jul. 2025',
        title: 'Reorganization and New Leadership',
        description: "UJLP reorganizes under a new leadership team and begins working to publish the Journal's inaugural edition.",
        category: 'Leadership'
    },
    {
        year: 'Dec. 2025',
        title: 'Inaugural Edition Published',
        description: 'UJLP publishes its inaugural edition.',
        category: 'Publication'
    },
    {
        year: 'Jan. 2026',
        title: 'First UJLP Symposium',
        description: "The first UJLP Symposium features the research of undergraduates published in the Journal's inaugural edition.",
        category: 'Symposium'
    }
];

const categoryMeta = {
    Legacy: {
        color: '#6B7280',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Legacy">
                <path d="M3 21V7h18v14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M7 10V6h3v4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M14 10V6h3v4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Establishment: {
        color: '#10B981',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Establishment">
                <path d="M12 2v20" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M5 12c2-4 6-6 6-6s4 2 6 6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Innovation: {
        color: '#6366F1',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Innovation">
                <path d="M12 2l3 7 7 3-7 3-3 7-3-7-7-3 7-3 3-7z" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Milestone: {
        color: '#F59E0B',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Milestone">
                <path d="M12 17.3L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" stroke="currentColor" strokeWidth="0.6" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Events: {
        color: '#EF4444',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Events">
                <rect x="3" y="5" width="18" height="16" rx="2" stroke="currentColor" strokeWidth="1.5"/>
                <path d="M16 3v4M8 3v4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Leadership: {
        color: '#8B5CF6',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Leadership">
                <path d="M12 2l3 7-3 3-3-3 3-7z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M12 12v10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Publication: {
        color: '#0EA5A4',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Publication">
                <path d="M4 19.5A2.5 2.5 0 0 0 6.5 22H20" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M20 2H8v16" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    },
    Symposium: {
        color: '#F97316',
        icon: (
            <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Symposium">
                <path d="M12 2v10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M5 12h14v6H5z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
        )
    }
};

function Timeline() {
    const containerRef = useRef(null);

    useEffect(() => {
        const items = containerRef.current?.querySelectorAll('.timeline-item');
        if (!items) return;

        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('in-view');
                    }
                });
            },
            { threshold: 0.2 }
        );

        items.forEach((item) => observer.observe(item));
        return () => observer.disconnect();
    }, []);

    return (
        <section className="timeline-section">
            <div className="section-content">
                <h2 className="timeline-heading">Our Journey</h2>

                <div className="timeline-visual">
                    <svg className="timeline-bg-svg" viewBox="0 0 1200 200" preserveAspectRatio="none">
                        <defs>
                            <linearGradient id="grad" x1="0" x2="1">
                                <stop offset="0%" stopColor="#6366F1" />
                                <stop offset="50%" stopColor="#10B981" />
                                <stop offset="100%" stopColor="#F97316" />
                            </linearGradient>
                        </defs>
                        <path d="M0,120 C300,0 900,240 1200,80" stroke="url(#grad)" strokeWidth="6" fill="none" strokeLinecap="round" opacity="0.12" />
                    </svg>

                    <div className="timeline-container" ref={containerRef}>
                        {timelineData.map((item, index) => {
                            const meta = categoryMeta[item.category] || { color: '#374151', icon: '✨' };
                            const side = index % 2 === 0 ? 'left' : 'right';

                            return (
                                <div key={index} className={`timeline-item ${side}`} style={{ '--accent': meta.color }}>
                                    <div className="timeline-point">
                                        <div className="timeline-dot" style={{ background: meta.color }}>
                                            <span className="timeline-icon" aria-hidden>{meta.icon}</span>
                                        </div>
                                    </div>

                                    <article className="timeline-card">
                                        <div className="card-header">
                                            <span className="card-category" style={{ background: meta.color }}>{item.category}</span>
                                            <h3 className="card-title">{item.title}</h3>
                                            <time className="card-date">{item.year}</time>
                                        </div>
                                        <p className="card-body">{item.description}</p>
                                    </article>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </section>
    );
}

export default Timeline;
